#!/usr/bin/env bash
set -Eeuo pipefail

if [[ -d "$PWD/index_sniper" && -x "$PWD/.venv/bin/python" ]]; then
  ROOT="$PWD"
else
  ROOT="$HOME/index-sniper-pro"
fi
PY="$ROOT/.venv/bin/python"
TS="$(date -u +%Y%m%dT%H%M%SZ)"
BACKUP="$ROOT/local_backups/vwap_backtest_v23_$TS"
TMP="$(mktemp -d)"
EXPECTED_SHA="9d099874e2a39c5165d9d2df0e4ff660fa33e543b12b7a4e6bbcf459c3cb4587"
cleanup(){ rm -rf "$TMP"; }
trap cleanup EXIT

if [[ ! -d "$ROOT/index_sniper" || ! -x "$PY" ]]; then
  echo "프로젝트 또는 .venv Python을 찾을 수 없습니다: $ROOT" >&2
  exit 1
fi
if [[ ! -f "$ROOT/config/vwap_scalper_v2.json" ]]; then
  echo "먼저 VWAP Scalper v2 SHADOW를 설치해야 합니다." >&2
  exit 2
fi
if ! command -v screen >/dev/null 2>&1; then
  echo "⚠️ screen 없음: 설치는 계속하지만 start 스크립트 대신 직접 실행해야 합니다." >&2
fi

mkdir -p "$BACKUP" "$ROOT/logs" "$ROOT/backtests/vwap_range_v23"
cat > "$TMP/payload.b64" <<'PAYLOAD'

PAYLOAD
base64 -d "$TMP/payload.b64" > "$TMP/payload.tar.gz"
ACTUAL_SHA="$(sha256sum "$TMP/payload.tar.gz" | awk '{print $1}')"
if [[ "$ACTUAL_SHA" != "$EXPECTED_SHA" ]]; then
  echo "payload checksum 불일치: $ACTUAL_SHA" >&2
  exit 4
fi
mkdir -p "$TMP/payload"
tar -xzf "$TMP/payload.tar.gz" -C "$TMP/payload"

FILES=(
  index_sniper/vwap_backtest_v23.py
  run_vwap_backtest_v23_full.sh
  run_vwap_backtest_v23_quick.sh
  status_vwap_backtest_v23.sh
  stop_vwap_backtest_v23.sh
  collect_vwap_backtest_v23_results.sh
  README_VWAP_BACKTEST_V23.md
)

for rel in "${FILES[@]}"; do
  if [[ -e "$ROOT/$rel" ]]; then
    mkdir -p "$BACKUP/$(dirname "$rel")"
    cp -a "$ROOT/$rel" "$BACKUP/$rel"
  fi
  mkdir -p "$ROOT/$(dirname "$rel")"
  cp -a "$TMP/payload/$rel" "$ROOT/$rel"
done

chmod 755 \
  "$ROOT/run_vwap_backtest_v23_full.sh" \
  "$ROOT/run_vwap_backtest_v23_quick.sh" \
  "$ROOT/status_vwap_backtest_v23.sh" \
  "$ROOT/stop_vwap_backtest_v23.sh" \
  "$ROOT/collect_vwap_backtest_v23_results.sh"
chmod 644 "$ROOT/index_sniper/vwap_backtest_v23.py" "$ROOT/README_VWAP_BACKTEST_V23.md"

cd "$ROOT"
PYTHONPATH="$ROOT" "$PY" -m py_compile index_sniper/vwap_backtest_v23.py
PYTHONPATH="$ROOT" "$PY" -m index_sniper.vwap_backtest_v23 self-test

cat <<EOF

✅ VWAP RANGE v2.3 백테스트 모듈 설치 완료

대상:
  현재 거래 가능한 시총 상위 10개
  최근 1년 / 최근 3년
  레버리지 1배~10배

정밀 1분봉 실행:
  bash run_vwap_backtest_v23_full.sh

빠른 3분봉 예비실행:
  bash run_vwap_backtest_v23_quick.sh

진행 확인:
  bash status_vwap_backtest_v23.sh

결과 묶기:
  bash collect_vwap_backtest_v23_results.sh

주의:
  이 백테스트는 현재 RANGE 모드만 검사합니다.
  1~3년 tick/order-book 완전 재현이 아니라 1분봉 보수적 근사입니다.
  백업: $BACKUP
EOF
